module reg_file(
    input clk,
    input rst,
    input we,
    input [2:0] ra1,
    input [2:0] ra2,
    input [2:0] wa,
    input [31:0] wd,

    output reg [31:0] rd1,
    output reg [31:0] rd2
);

reg [31:0] mem[7:0];

always@(posedge clk or posedge rst)
begin
    if(rst)
    begin
        mem[0] <= 0;
        mem[1] <= 0;
        mem[2] <= 0;
        mem[3] <= 0;
        mem[4] <= 0;
        mem[5] <= 0;
        mem[6] <= 0;
        mem[7] <= 0;
    end
    else if(we)
        mem[wa] <= wd;
end

always@(*)
begin
    rd1 = mem[ra1];
    rd2 = mem[ra2];
end

endmodule
